framework_css:
/* Design system variables */
:root {
  /* Brand colors taken from the design palette */
  --color-primary-900: #5D0010; /* deep maroon header */
  --color-primary-800: #7A0018; /* lighter maroon */

  --color-secondary-100: #F2C9C5; /* soft rose */
  --color-secondary-400: #C27E76; /* warm rose-brown */

  --color-accent-gold: #F2B544; /* ceremonial gold */

  --color-neutral-0: #FFFFFF;
  --color-neutral-25: #F7F4F2; /* parchment off-white */
  --color-neutral-900: #222222;

  --color-success: #3B7D5B;
  --color-error: #B6383A;
  --color-warning: #D68A25;
  --color-info: #2A5D87;

  /* Typography */
  --font-heading: 'Playfair Display', Georgia, serif;
  --font-body: 'Lora', 'Times New Roman', serif;

  --font-size-root: 16px;
  --font-size-body: 1rem; /* 16px */
  --font-size-small: 0.875rem; /* 14px */
  --font-size-nav: 0.875rem; /* 14px */
  --font-size-footer: 0.875rem; /* 14px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --space-0: 0;
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --max-width-page: 1200px;
  --header-height-desktop: 72px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: var(--font-size-root);
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-900);
  background-color: var(--color-neutral-25);
}

.page-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

ul {
  list-style: none;
  margin: 0;
  padding: 0;
}

a {
  color: inherit;
}

a:hover,
a:focus-visible {
  text-decoration: none;
}

:focus-visible {
  outline: 2px solid var(--color-accent-gold);
  outline-offset: 2px;
}

.sr-only {
  border: 0;
  clip: rect(0 0 0 0);
  height: 1px;
  margin: -1px;
  overflow: hidden;
  padding: 0;
  position: absolute;
  width: 1px;
}

/* Header */

.site-header {
  background-color: var(--color-primary-900);
  color: var(--color-neutral-0);
}

.header-inner {
  max-width: var(--max-width-page);
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-inline: var(--space-5);
  height: var(--header-height-desktop);
}

.brand {
  display: inline-flex;
  align-items: center;
  text-decoration: none;
  color: inherit;
}

.brand-mark {
  width: 44px;
  height: 44px;
  border-radius: 999px;
  border: 2px solid var(--color-secondary-100);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-style: italic;
  font-weight: 600;
  font-size: 1.1rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-secondary-100);
  background: radial-gradient(circle at 30% 20%, var(--color-accent-gold) 0, var(--color-secondary-400) 45%, var(--color-primary-900) 100%);
  box-shadow: 0 0 0 2px rgba(0, 0, 0, 0.1);
}

.primary-nav {
  display: flex;
  align-items: center;
}

.nav-list {
  display: flex;
  align-items: center;
  gap: 24px;
}

.nav-item {
  display: flex;
}

.nav-link {
  position: relative;
  display: inline-block;
  padding-block: 4px;
  font-family: var(--font-body);
  font-size: var(--font-size-nav);
  font-weight: 400;
  letter-spacing: 0.03em;
  color: var(--color-neutral-0);
  text-decoration: none;
  white-space: nowrap;
}

.nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: 0;
  width: 0;
  height: 1px;
  background-color: var(--color-accent-gold);
  transition: width 0.2s ease-out;
}

.nav-link:hover::after,
.nav-link:focus-visible::after {
  width: 100%;
}

.nav-link:hover,
.nav-link:focus-visible {
  color: var(--color-secondary-100);
}

/* Main layout placeholder */

.site-main {
  flex: 1 0 auto;
  width: 100%;
  padding-inline: var(--space-3);
  padding-block: var(--space-6);
}

@media (min-width: 768px) {
  .site-main {
    padding-inline: var(--space-5);
    padding-block: var(--space-7);
  }
}

/* Footer */

.site-footer {
  margin-top: auto;
  background: linear-gradient(180deg, var(--color-primary-900) 0%, #3A0009 100%);
  color: var(--color-secondary-100);
}

.footer-inner {
  max-width: var(--max-width-page);
  margin: 0 auto;
  padding-inline: var(--space-5);
  padding-top: var(--space-5);
  padding-bottom: var(--space-4);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

.footer-brand-block {
  display: flex;
  justify-content: flex-start;
}

.footer-brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  text-decoration: none;
  color: inherit;
}

.footer-brand-mark {
  width: 40px;
  height: 40px;
  font-size: 1rem;
}

.footer-brand-text {
  font-family: var(--font-heading);
  font-style: italic;
  font-weight: 500;
  font-size: 1.05rem;
  letter-spacing: 0.04em;
}

.footer-nav {
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding-top: var(--space-4);
}

.footer-links {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2) var(--space-5);
}

.footer-item {
  flex: 0 0 auto;
}

.footer-link {
  font-family: var(--font-body);
  font-size: var(--font-size-footer);
  text-decoration: none;
  color: rgba(255, 255, 255, 0.86);
  transition: color 0.15s ease-out;
}

.footer-link:hover,
.footer-link:focus-visible {
  color: var(--color-accent-gold);
}

.footer-bottom {
  border-top: 1px solid rgba(0, 0, 0, 0.35);
  background-color: #2A0007;
}

.footer-bottom-inner {
  max-width: var(--max-width-page);
  margin: 0 auto;
  padding-inline: var(--space-5);
  padding-block: var(--space-3);
}

.footer-meta {
  margin: 0;
  font-family: var(--font-body);
  font-size: 0.8rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.7);
}

/* Responsive adjustments */

@media (max-width: 959px) {
  .header-inner {
    padding-inline: var(--space-3);
  }

  .nav-list {
    gap: 16px;
  }

  .nav-link {
    font-size: 0.8rem;
  }

  .footer-inner {
    padding-inline: var(--space-3);
  }
}

@media (max-width: 720px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
    justify-content: center;
    gap: var(--space-2);
    height: auto;
    padding-block: var(--space-3);
  }

  .nav-list {
    flex-wrap: wrap;
    row-gap: 8px;
  }

  .footer-links {
    flex-direction: column;
    gap: 6px;
  }
}
